def is_match(s: str, p: str) -> bool:
    # Create a DP table where dp[i][j] represents if s[0:i] matches p[0:j]
    m, n = len(s), len(p)
    dp = [[False] * (n + 1) for _ in range(m + 1)]

    # Empty string matches empty pattern
    dp[0][0] = True

    # Handle patterns like a*, a*b*, a*b*c* which can match empty string
    for j in range(2, n + 1):
        if p[j - 1] == '*':
            dp[0][j] = dp[0][j - 2]

    # Fill the DP table
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if p[j - 1] == '*':
                # '*' matches zero or more of the preceding element
                # Case 1: Match zero of the preceding element
                dp[i][j] = dp[i][j - 2]

                # Case 2: Match one or more of the preceding element
                # Check if the character before '*' matches current char in s
                if p[j - 2] == '.' or p[j - 2] == s[i - 1]:
                    dp[i][j] = dp[i][j] or dp[i - 1][j]
            else:
                # Current characters must match (either exact match or '.')
                if p[j - 1] == '.' or p[j - 1] == s[i - 1]:
                    dp[i][j] = dp[i - 1][j - 1]

    return dp[m][n]
```

