def is_number(s: str) -> bool:
    if not s:
        return False

    i = 0

    # Check optional leading sign
    if s[i] in ['+', '-']:
        i += 1

    # Must have at least one digit before or after decimal point
    if i == len(s):
        return False

    # Check for digits before decimal point
    has_digits_before_decimal = False
    while i < len(s) and s[i].isdigit():
        has_digits_before_decimal = True
        i += 1

    # Check for decimal point
    has_digits_after_decimal = False
    if i < len(s) and s[i] == '.':
        i += 1
        while i < len(s) and s[i].isdigit():
            has_digits_after_decimal = True
            i += 1

    # Must have digits either before or after decimal point
    if not (has_digits_before_decimal or has_digits_after_decimal):
        return False

    # Check for exponent
    if i < len(s) and s[i] in ['e', 'E']:
        i += 1

        # Exponent must have at least one digit
        if i == len(s):
            return False

        # Check optional sign in exponent
        if s[i] in ['+', '-']:
            i += 1

        # Must have at least one digit in exponent
        if i == len(s) or not s[i].isdigit():
            return False

        while i < len(s) and s[i].isdigit():
            i += 1

    # All characters must be consumed
    return i == len(s)
